const res = await fetch("https://idx.quantyralabs.cc/api/v1/comps/run?dataset=stellar", {
  method: "POST",
  headers: {
    "Authorization": "Bearer ${process.env.IDX_API_TOKEN}",
    "Content-Type": "application/json",
    "X-Domain-Slug": "${process.env.IDX_DOMAIN_SLUG}"
  },
  body: JSON.stringify({
        "subject": {
          "type": "off_market",
          "lat": 27.916,
          "lng": -82.769,
          "bedrooms": 3,
          "bathrooms": 2,
          "living_area_sqft": 1800
        },
        "mode": "A",
        "scope": { "type": "radius", "radius_miles": 3 },
        "filters": { "max_sold_comps": 3, "sold_months_back": 12 }
      }),
});
if (!res.ok) throw new Error(`API ${res.status}`);
const data = await res.json();
